import org.owasp.esapi.ESAPI;
import org.owasp.esapi.Encoder;

public class XSSFixedCode {

    public static void main(String[] args) {
        // Simulating user input from an untrusted source
        String userInput = "<script>alert('XSS attack!')</script>";

        // Encoding the user input to prevent XSS attacks
        Encoder encoder = ESAPI.encoder();
        String encodedUserInput = encoder.encodeForHTML(userInput);

        // Displaying the properly encoded user input on a web page
        String htmlContent = "<div>" + encodedUserInput + "</div";

        System.out.println(htmlContent);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
